constexpr auto DEF_VECTOR_SIZE_PER_THREAD = 4 * 1024 * 1024;

using ArgParams = struct { unsigned int vecwidth; };

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

// CUDA Kernel implementations
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_cuda(Element* data, Element* sum_out, size_t len) {
  Element sum = 0;
  Element f = data[0];

  size_t idx = blockIdx.x * static_chunk_size + threadIdx.x;
  if (idx < len) {
    Element t = data[idx];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }

  // Simple reduction within block (assuming 1 thread per block for simplicity or use atomic)
  // For exact reproduction of logic with parallelism, we map each thread to one element
  // and accumulate globally.
  if (idx < len) {
    atomicAdd(sum_out, sum);
  }
}

// Alternative kernel matching the non-BASELINE_IMPL logic (8-wide)
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_cuda_8(Element* data, Element* sum_out, size_t len) {
  Element sum = 0;
  Element f[8];
  for(int k=0; k<8; k++) f[k] = data[k]; // Simplified: using first 8 elements as f

  size_t idx = blockIdx.x * static_chunk_size + threadIdx.x;
  if (idx < len) {
    Element t[8];
    for(int k=0; k<8; k++) t[k] = data[idx];

    size_t iterations = compute_iterations / 8;
    for (size_t j = 0; j < iterations; j++) {
      t[0] = t[0] * t[0] + f[0];
      t[1] = t[1] * t[1] + f[1];
      t[2] = t[2] * t[2] + f[2];
      t[3] = t[3] * t[3] + f[3];
      t[4] = t[4] * t[4] + f[4];
      t[5] = t[5] * t[5] + f[5];
      t[6] = t[6] * t[6] + f[6];
      t[7] = t[7] * t[7] + f[7];
    }

    if (compute_iterations % 8 > 0) t[0] = t[0] * t[0] + f[0];
    if (compute_iterations % 8 > 1) t[1] = t[1] * t[1] + f[1];
    if (compute_iterations % 8 > 2) t[2] = t[2] * t[2] + f[2];
    if (compute_iterations % 8 > 3) t[3] = t[3] * t[3] + f[3];
    if (compute_iterations % 8 > 4) t[4] = t[4] * t[4] + f[4];
    if (compute_iterations % 8 > 5) t[5] = t[5] * t[5] + f[5];
    if (compute_iterations % 8 > 6) t[6] = t[6] * t[6] + f[6];

    sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];

    atomicAdd(sum_out, sum);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src, Element* d_src) {
  // Copy seeds to device array if needed, but original uses src[0] etc.
  // We assume src is already populated on device or we copy it.
  // The original code overwrites src[0] with sum at the end.

  Element* d_sum;
  cudaMalloc(&d_sum, sizeof(Element));
  cudaMemset(d_sum, 0, sizeof(Element));

  constexpr size_t static_chunk_size = 4096;
  size_t total_threads = len; 
  // Map threads directly to elements for simplicity to match reduction logic
  // Or use block structure. Let's use simple mapping: 1 thread per element logic inside block

  // Launch configuration
  int blockSize = 256;
  int numBlocks = (len + blockSize - 1) / blockSize;

  // Choose kernel based on implementation style (defaulting to 8-wide as in source non-BASELINE)
  // Since BASELINE_IMPL is not defined in source, we use the 8-wide version.
  bench_block_cuda_8<Element, compute_iterations, static_chunk_size><<<numBlocks, blockSize>>>(d_src, d_sum, len);

  cudaDeviceSynchronize();

  Element host_sum;
  cudaMemcpy(&host_sum, d_sum, sizeof(Element), cudaMemcpyDeviceToHost);

  *src = host_sum; // Update host/src value as per original

  cudaFree(d_sum);
  return len;
}

using benchmark_clock = std::chrono::steady_clock;

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);

  double* d_ptr;
  cudaMalloc(&d_ptr, size);
  // Initialize with some data (seed)
  double seed1 = 1.0, seed2 = -1.0;
  // Simple initialization kernel or copy
  std::vector<double> tmp(num_elements, 1.0);
  cudaMemcpy(d_ptr, tmp.data(), size, cudaMemcpyHostToDevice);

  auto timer_start = benchmark_clock::now();

  bench_cuda<double, 16>(num_elements, seed1, seed2, (double*)c, d_ptr);

  auto timer_duration = benchmark_clock::now() - timer_start;
  cudaFree(d_ptr);
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  cudaDeviceSynchronize();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  // CUDA doesn't have "threads" count in the same way, but we simulate the loop structure
  // The original runs 19 times then 9 times with half threads. 
  // In CUDA, we just run the operation multiple times to find min time.

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  // Simulating the "half thread" part is not meaningful in CUDA kernel launch context 
  // unless we change block/grid size. We'll just run more iterations to be safe or skip.
  // To strictly follow "min_element" logic of original:
  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  // Allocate device memory
  float *d_c_as_float;
  cudaMalloc(&d_c_as_float, cs.element_count<float>() * sizeof(float));
  // Init
  std::vector<float> init_f(cs.element_count<float>(), 1.0f);
  cudaMemcpy(d_c_as_float, init_f.data(), cs.element_count<float>() * sizeof(float), cudaMemcpyHostToDevice);

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, (float*)c, d_c_as_float);
    });
  });

  double *d_c_as_double;
  cudaMalloc(&d_c_as_double, cs.element_count<double>() * sizeof(double));
  std::vector<double> init_d(cs.element_count<double>(), 1.0);
  cudaMemcpy(d_c_as_double, init_d.data(), cs.element_count<double>() * sizeof(double), cudaMemcpyHostToDevice);

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(cs.element_count<double>(), 1., -1., (double*)c, d_c_as_double);
    });
  });

  int *d_c_as_int;
  cudaMalloc(&d_c_as_int, cs.element_count<int>() * sizeof(int));
  std::vector<int> init_i(cs.element_count<int>(), 1);
  cudaMemcpy(d_c_as_int, init_i.data(), cs.element_count<int>() * sizeof(int), cudaMemcpyHostToDevice);

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(cs.element_count<int>(), 1, -1, (int*)c, d_c_as_int);
    });
  });

  cudaFree(d_c_as_float);
  cudaFree(d_c_as_double);
  cudaFree(d_c_as_int);

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;
}


template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

