  // Initialize memory on GPU
  int* d_c;
  cudaMalloc(&d_c, size);
  cudaMemset(d_c, 0, size);
  // Copy back to host 'c' if needed by subsequent logic, though original writes to host 'c'
  cudaMemcpy(c, d_c, size, cudaMemcpyDeviceToHost);
  cudaFree(d_c);

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
