            << std::endl;
}

int main(int argc, char* argv[]) {
  std::cout << "mixbench-cuda (" << VERSION_INFO << ")" << std::endl;

  // Get CUDA device info to mimic thread count logic roughly or just use fixed
  int deviceCount = 0;
  cudaGetDeviceCount(&deviceCount);
  if (deviceCount == 0) {
      std::cout << "No CUDA devices found!" << std::endl;
      return 1;
  }

  cudaDeviceProp prop;
  cudaGetDeviceProperties(&prop, 0);
  int hardware_concurrency = prop.multiProcessorCount * 1024; // Rough estimate of parallelism

  ArgParams args{static_cast<unsigned int>(
      hardware_concurrency * DEF_VECTOR_SIZE_PER_THREAD / (1024 * 1024))};

  if (!argument_parsing(argc, argv, &args)) {
    std::cout << "Usage: mixbench-cuda [options] [array size(1024^2)]"
              << std::endl
              << std::endl
              << "Options:" << std::endl
              << "  -h or --help              Show this message" << std::endl;

    exit(1);
  }

  std::cout << "Use \"-h\" argument to see available options" << std::endl;

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;

  std::unique_ptr<std::byte[]> c;
  c.reset(new (std::align_val_t(64)) std::byte[VEC_WIDTH * sizeof(double)]);

  std::cout << "Working memory size: " << args.vecwidth * sizeof(double) << "MB"
            << std::endl;
  std::cout << "Total threads (simulated): " << hardware_concurrency << std::endl;

  mixbenchCPU(c.get(), VEC_WIDTH * sizeof(double));

  return 0;
}
